/**
 * renderLieferschein.js
 * Lieferschein-Vorlage der Saatgut- u. Agrarservice Beesenstedt GmbH
 * fuer die Ernte-App. Framework-unabhaengig: gibt einen kompletten,
 * druckfertigen HTML-String zurueck. Logos sind eingebettet (kein externer Pfad).
 *
 *   import { renderLieferschein } from './renderLieferschein.js';
 *   const html = renderLieferschein(daten);
 *
 * Drucken z. B. ueber ein verstecktes iframe -> window.print(),
 * oder serverseitig (Puppeteer / weasyprint) zu PDF rendern.
 *
 * Raps: enthaelt der Artikel "raps", wird die Nachhaltigkeits-Zertifikatnummer
 * automatisch ausgegeben. Ueberschreibbar mit daten.istRaps (true/false).
 */

export const REDCERT_NACHHALTIGKEIT = 'EU-REDcert-505-81711102';

const LOGOS = {
  "header": "data:image/png;base64,",
  "bio": "data:image/png;base64,",
  "gmp": "data:image/png;base64,",
  "redcert": "data:image/png;base64,"
};

const CSS = `/* ===========================================================================
   Lieferschein – Saatgut- u. Agrarservice Beesenstedt GmbH
   Druckvorlage A4 hoch. Platzhalter {{feld}} werden vom Waagenprogramm ersetzt.
   Ein Lieferschein = eine Verwiegung = genau ein Artikel.
   Raps: Block zwischen RAPS-START / RAPS-END nur ausgeben, wenn Artikel = Raps.
   =========================================================================== */

:root {
  --gruen:      #27985B;
  --gruen-hell: #EDF6F1;
  --linie:      #000;
  --hairline:   #BFBFBF;
  --grau:       #808080;
  --seite-b:    210mm;
  --rand:       12mm;
}

@page { size: A4 portrait; margin: 10mm 12mm; }

* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: "Open Sans", "Segoe UI", Arial, sans-serif;
  font-size: 10pt;
  color: #000;
  -webkit-print-color-adjust: exact;
  print-color-adjust: exact;
}

.blatt {
  width: var(--seite-b);
  min-height: 297mm;
  padding: var(--rand);
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  background: #fff;
}

@media screen {
  body { background: #e9e9e9; padding: 20px 0; }
  .blatt { box-shadow: 0 2px 14px rgba(0,0,0,.25); margin-bottom: 20px; }
}
@media print {
  body { background: none; padding: 0; }
  .blatt { width: auto; min-height: 277mm; padding: 0; box-shadow: none; margin: 0; }
}

/* ---------------------------------------------------------------- Kopf */
.kopf { display: flex; justify-content: space-between; align-items: flex-start; }
.kopf-logo img { height: 28mm; width: auto; }
.kopf-kontakt { margin-top: 2mm; font-size: 8pt; color: var(--grau); }
.titel { font-size: 28pt; font-weight: 700; line-height: 1; letter-spacing: -.5pt; }

/* ---------------------------------------------------------------- Metablock */
.meta { display: flex; justify-content: space-between; gap: 8mm; margin-top: 6mm; }

.anschrift { flex: 1 1 auto; padding-top: 4mm; }
.anschrift .label { font-size: 8pt; font-weight: 600; color: var(--grau); margin-bottom: 1.5mm; }
.anschrift .zeile { min-height: 4.6mm; line-height: 4.6mm; }
.anschrift .land  { font-weight: 700; }

.felder { flex: 0 0 78mm; border-collapse: collapse; align-self: flex-start; }
.felder td { border: .75pt solid var(--linie); padding: 1mm 2mm; height: 6.4mm; }
.felder td.k { font-weight: 600; width: 48mm; }
.felder td.v { text-align: right; }

/* ---------------------------------------------------------------- Artikel */
table.pos { width: 100%; border-collapse: collapse; margin-top: 5mm; }
table.pos th {
  background: var(--gruen); color: #fff; font-weight: 600; font-size: 10pt;
  border: .75pt solid var(--linie); padding: 1.4mm 2mm; height: 6.4mm;
}
table.pos td { border: .75pt solid var(--linie); padding: 1.4mm 2mm; height: 7mm; }
table.pos th.artikel,  table.pos td.artikel  { text-align: left;   width: 46%; }
table.pos th.kontrakt, table.pos td.kontrakt { text-align: center; width: 18%; }
table.pos th.herkunft, table.pos td.herkunft { text-align: center; width: 12%; }
table.pos th.einheit,  table.pos td.einheit  { text-align: center; width: 10%; }
table.pos th.menge,    table.pos td.menge    { text-align: right;  width: 14%; }

/* ---------------------------------------------------------------- Blöcke */
.block { border: .75pt solid var(--linie); margin-top: 4mm; }
.block > h2 {
  background: var(--gruen); color: #fff;
  font-size: 9pt; font-weight: 600; padding: 1mm 2mm;
}
.raster { display: grid; grid-template-columns: 26mm 1fr 34mm 1fr; }
.raster > div { padding: 1.2mm 2mm; min-height: 6mm; font-size: 9pt; }
.raster > .k { font-weight: 600; color: var(--grau); }
.raster > .v { border-bottom: .5pt solid var(--hairline); }
.raster > .v.stark { font-weight: 700; }

/* Sonstige Angaben – Freitext je Verwiegung */
.sonstiges-inhalt { padding: 2mm; }
.raps-cert {
  display: inline-block;
  background: var(--gruen-hell);
  border: .5pt solid var(--gruen);
  border-radius: 1mm;
  padding: 1mm 2.5mm;
  font-size: 9pt;
  font-weight: 700;
  margin-bottom: 2mm;
}
.raps-cert .label { color: var(--gruen); font-weight: 600; }
.freitext { min-height: 14mm; font-size: 9pt; line-height: 1.5; white-space: pre-wrap; }

/* ---------------------------------------------------------------- Unterschriften */
/* margin-top:auto schiebt Unterschriften + Fußzeile als Gruppe an den Seitenfuß */
.unterschriften { display: flex; gap: 14mm; margin-top: auto; padding-top: 12mm; }
.unterschriften > div { flex: 1; }
.unterschriften .linie { border-bottom: .75pt solid var(--linie); height: 8mm; }
.unterschriften .wer { font-size: 8pt; color: var(--grau); padding-top: 1mm; }

/* ---------------------------------------------------------------- Fußzeile */
.fuss {
  margin-top: 5mm; padding-top: 2.5mm; border-top: .75pt solid var(--linie);
  display: flex; justify-content: space-between; align-items: center; gap: 6mm;
}
.zertifikate { display: flex; align-items: center; gap: 5mm; flex: 0 0 auto; }
.zertifikate img { width: auto; }
.zertifikate img.bio     { height: 9mm; }
.zertifikate img.gmp     { height: 11mm; }
.zertifikate img.redcert { height: 8mm; }
.impressum { font-size: 6.5pt; line-height: 1.5; color: var(--grau); text-align: right; }`;

function esc(v) {
  return String(v ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

/**
 * @param {Object} d Datenobjekt (siehe README, Abschnitt "Datenobjekt")
 * @returns {string} vollstaendiges HTML-Dokument (eine A4-Seite)
 */
export function renderLieferschein(d = {}) {
  // Zertifikate: explizit als d.zertifikate = [{label, nr}], sonst Fallback auf
  // Raps-Automatik (Nachhaltigkeits-Zertifikat), damit ältere Aufrufe gleich bleiben.
  const zerts = Array.isArray(d.zertifikate)
    ? d.zertifikate.filter(z => z && z.label)
    : ((d.istRaps ?? /raps/i.test(d.artikel || ''))
        ? [{ label: 'Nachhaltigkeits-Zertifikat', nr: REDCERT_NACHHALTIGKEIT }]
        : []);
  const rapsBlock = zerts.map(z =>
    `<div style="margin-bottom:1.5mm">
      <span class="raps-cert"><span class="label">${esc(z.label)}${z.nr ? ':' : ''}</span> ${esc(z.nr || '')}</span>
      ${z.hinweis ? `<div style="font-size:9pt;font-weight:700;margin-top:1mm">${esc(z.hinweis)}</div>` : ''}
    </div>`
  ).join('');

  return `<!DOCTYPE html>
<html lang="de">
<head>
<meta charset="utf-8">
<title>Lieferschein ${esc(d.ls_nummer)}</title>
<style>${CSS}</style>
</head>
<body>
<div class="blatt">

  <header class="kopf">
    <div class="kopf-logo">
      <img src="${LOGOS.header}" alt="Saatgut- u. Agrarservice Beesenstedt GmbH">
      <div class="kopf-kontakt">Tel. +49 34773 39001 &nbsp;·&nbsp; office@landgut-nuscheler.de</div>
    </div>
    <div class="titel">Lieferschein</div>
  </header>

  <section class="meta">
    <div class="anschrift">
      <div class="label">Lieferanschrift</div>
      <div class="zeile">${esc(d.empf_name)}</div>
      <div class="zeile">${esc(d.empf_zusatz)}</div>
      <div class="zeile">${esc(d.empf_strasse)}</div>
      <div class="zeile">${esc(d.empf_plz_ort)}</div>
      <div class="zeile land">${esc(d.empf_land)}</div>
    </div>
    <table class="felder">
      <tr><td class="k">Lieferschein-Nr.</td> <td class="v">${esc(d.ls_nummer)}</td></tr>
      <tr><td class="k">Datum</td>            <td class="v">${esc(d.datum)}</td></tr>
    </table>
  </section>

  <table class="pos">
    <thead>
      <tr>
        <th class="artikel">Artikel</th>
        <th class="kontrakt">Kontrakt</th>
        <th class="herkunft">Herkunft</th>
        <th class="einheit">Einheit</th>
        <th class="menge">Menge</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td class="artikel">${esc(d.artikel)}</td>
        <td class="kontrakt">${esc(d.kontrakt)}</td>
        <td class="herkunft">${esc(d.herkunft)}</td>
        <td class="einheit">${esc(d.einheit)}</td>
        <td class="menge">${esc(d.menge)}</td>
      </tr>
    </tbody>
  </table>

  <section class="block">
    <h2>Verwiegung</h2>
    <div class="raster">
      <div class="k">Brutto (kg)</div><div class="v">${esc(d.brutto_kg)}</div>
      <div class="k">Erstwiegung</div><div class="v">${esc(d.zeit_erstwiegung)}</div>
      <div class="k">Tara (kg)</div><div class="v">${esc(d.tara_kg)}</div>
      <div class="k">Zweitwiegung</div><div class="v">${esc(d.zeit_zweitwiegung)}</div>
      <div class="k">Netto (kg)</div><div class="v stark">${esc(d.netto_kg)}</div>
      <div class="k">Waage-Nr. / Eichnr.</div><div class="v">${esc(d.waage_nr)}</div>
    </div>
  </section>

  <section class="block">
    <h2>Spedition &amp; Kennzeichen</h2>
    <div class="raster">
      <div class="k">Spedition</div><div class="v">${esc(d.spedition)}</div>
      <div class="k">Kennzeichen</div><div class="v">${esc(d.kennzeichen)}</div>
    </div>
  </section>

  <section class="block">
    <h2>Sonstige Angaben</h2>
    <div class="sonstiges-inhalt">
      ${rapsBlock}
      <div class="freitext">${esc(d.sonstige_angaben)}</div>
    </div>
  </section>

  <section class="unterschriften">
    <div>
      <div class="linie"></div>
      <div class="wer">Saatgut- u. Agrarservice Beesenstedt GmbH</div>
    </div>
    <div>
      <div class="linie"></div>
      <div class="wer">Lieferant / Kunde</div>
    </div>
  </section>

  <footer class="fuss">
    <div class="zertifikate">
      <img class="bio"     src="${LOGOS.bio}"     alt="EU-Bio">
      <img class="gmp"     src="${LOGOS.gmp}"     alt="GMP+ FSA certified">
      <img class="redcert" src="${LOGOS.redcert}" alt="REDcert EU">
    </div>
    <div class="impressum">
      Saatgut- u. Agrarservice Beesenstedt GmbH · Bahnhofstrasse 11 · 06198 Salzatal OT Beesenstedt · Tel. +49 34773 39001 · office@landgut-nuscheler.de<br>
      Registergericht Stendal HRB 210422 · Geschäftsführer Johann Nuscheler · Steuernummer 110/299/41574 · USt-IdNr. DE139712562 · Öko-Kontrollstelle DE-ÖKO-006<br>
      Saalesparkasse Halle · IBAN DE17 8005 3762 0387 3018 20 · BIC NOLADE21HAL
    </div>
  </footer>

</div>
</body>
</html>`;
}
